<?php $__env->startSection('title','Payments'); ?>
<?php $__env->startSection('content'); ?><div class="table-card"><table class="table"><tr><th>Order</th><th>Customer</th><th>Method</th><th>Transaction ID</th><th>Status</th><th></th></tr><?php $__currentLoopData = $payments; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $payment): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><tr><td><?php echo e($payment->order->order_number); ?></td><td><?php echo e($payment->order->user->name); ?></td><td><?php echo e(str_replace('_',' ',$payment->method)); ?></td><td><?php echo e($payment->transaction_id ?? '-'); ?></td><td><span class="badge text-bg-info"><?php echo e($payment->status); ?></span></td><td><form class="d-flex gap-2" method="post" action="<?php echo e(route('admin.payments.update',$payment)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('PUT'); ?><select class="form-select form-select-sm" name="status"><?php $__currentLoopData = ['pending','paid','failed']; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $status): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><option <?php if($payment->status==$status): echo 'selected'; endif; ?>><?php echo e($status); ?></option><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></select><button class="btn btn-sm btn-primary">Save</button></form></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></table><?php echo e($payments->links()); ?></div><?php $__env->stopSection(); ?>

